import React, { useState } from 'react';

const links = [
  { label: 'Home', href: '#Introduction' },
  { label: 'About Me', href: '#About-Me' },
  { label: 'Education', href: '#Education' },
  { label: 'Experience', href: '#Experience' },
  { label: 'Skills', href: '#Skills' },
  { label: 'My Projects', href: '#Projects' },
  { label: 'Contact', href: '#Contact' },
];

const PS_SYMBOLS = ['✕', '○', '□', '△'];

const Navbar = () => {
  const [hovered, setHovered] = useState(null);

  return (
    <nav
      className="fixed top-0 left-0 w-full z-50 flex flex-wrap gap-6 px-6 py-4 shadow-lg"
      style={{
        background: '#000',
        borderBottom: '1px solid #0d6efd',
        fontFamily: "'Orbitron', sans-serif",
      }}
    >
      <span
        className="font-bold text-base mr-2 hidden md:inline-block"
        style={{ color: 'rgba(255,255,255,0.25)', letterSpacing: '4px', fontSize: '12px' }}
      >
        ✕ ○ □ △
      </span>

      {links.map((link, idx) => {
        const symbol = PS_SYMBOLS[idx % 4];
        const isHovered = hovered === link.href;

        return (
          <a
            key={link.href}
            href={link.href}
            onMouseEnter={() => setHovered(link.href)}
            onMouseLeave={() => setHovered(null)}
            className="font-bold text-sm transition-all duration-300 inline-flex items-center gap-1"
            style={{
              color: isHovered ? '#fff' : 'rgba(255,255,255,0.7)',
              transform: isHovered ? 'translateY(-2px)' : 'none',
              textShadow: isHovered ? `0 0 10px #0d6efd` : 'none',
              fontFamily: "'Orbitron', sans-serif",
            }}
          >
            <span style={{ color: '#0d6efd', fontSize: '10px' }}>
              {symbol}
            </span>
            {link.label}
          </a>
        );
      })}
    </nav>
  );
};

export default Navbar;
